import { t as prisma } from "../../../../../../chunks/prisma.js";
import { error, fail, redirect } from "@sveltejs/kit";
//#region src/routes/(protected)/dashboard/blog/[id]/+page.server.ts
var load = async ({ params }) => {
	const post = await prisma.blogPost.findUnique({
		where: { id: params.id },
		include: { category: true }
	});
	if (!post) throw error(404, "Blog post not found");
	return {
		post,
		categories: await prisma.category.findMany({ orderBy: { name: "asc" } })
	};
};
var actions = {
	update: async ({ request, params }) => {
		const formData = await request.formData();
		const title = formData.get("title");
		const content = formData.get("content");
		const image = formData.get("image");
		const categoryId = formData.get("categoryId");
		const published = formData.get("published") === "true";
		if (!title || !content || !categoryId) return fail(400, {
			error: "Title, content, and category are required",
			values: {
				title,
				content,
				image,
				categoryId,
				published
			}
		});
		const slug = title.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/(^-|-$)+/g, "");
		try {
			const finalSlug = await prisma.blogPost.findFirst({ where: {
				slug,
				NOT: { id: params.id }
			} }) ? `${slug}-${Math.floor(Math.random() * 1e3)}` : slug;
			await prisma.blogPost.update({
				where: { id: params.id },
				data: {
					title,
					slug: finalSlug,
					content,
					image,
					published,
					categoryId
				}
			});
		} catch (err) {
			console.error(err);
			return fail(500, { error: "Failed to update blog post" });
		}
		throw redirect(303, "/dashboard/blog");
	},
	delete: async ({ params }) => {
		try {
			await prisma.blogPost.delete({ where: { id: params.id } });
		} catch (err) {
			console.error(err);
			return fail(500, { error: "Failed to delete blog post" });
		}
		throw redirect(303, "/dashboard/blog");
	}
};
//#endregion
export { actions, load };
